// commonjs 规范引入 express
const express = require('express')

// 实例化 express
const app = express()
app.use(express.json()) // 配置获取body数据

// 声明端口变量
const port = 3000

app.get('/', (request, response) => {
  // req => request 请求体
  // res => response 响应体

  console.log(request.url) // 获取请求地址
  console.log(request.method) // 请求方式
  console.log(request.headers) // 请求头

  // send => 发送
  response.status(500).send('nihao')
})

